files.content:
@custom-variant dark (&:is(.dark *));

@theme inline {
    --font-heading: var(--font-sans);
    --font-sans: "Segoe UI Variable", "Segoe UI", system-ui, -apple-system, BlinkMacSystemFont, sans-serif;
    --color-sidebar-ring: var(--sidebar-ring);
    --color-sidebar-border: var(--sidebar-border);
    --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
    --color-sidebar-accent: var(--sidebar-accent);
    --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
    --color-sidebar-primary: var(--sidebar-primary);
    --color-sidebar-foreground: var(--sidebar-foreground);
    --color-sidebar: var(--sidebar);
    --color-chart-5: var(--chart-5);
    --color-chart-4: var(--chart-4);
    --color-chart-3: var(--chart-3);
    --color-chart-2: var(--chart-2);
    --color-chart-1: var(--chart-1);
    --color-ring: var(--ring);
    --color-input: var(--input);
    --color-border: var(--border);
    --color-destructive: var(--destructive);
    --color-accent-foreground: var(--accent-foreground);
    --color-accent: var(--accent);
    --color-muted-foreground: var(--muted-foreground);
    --color-muted: var(--muted);
    --color-secondary-foreground: var(--secondary-foreground);
    --color-secondary: var(--secondary);
    --color-primary-foreground: var(--primary-foreground);
    --color-primary: var(--primary);
    --color-popover-foreground: var(--popover-foreground);
    --color-popover: var(--popover);
    --color-card-foreground: var(--card-foreground);
    --color-card: var(--card);
    --color-foreground: var(--foreground);
    --color-background: var(--background);
    --radius-sm: calc(var(--radius) * 0.6);
    --radius-md: calc(var(--radius) * 0.8);
    --radius-lg: var(--radius);
    --radius-xl: calc(var(--radius) * 1.4);
    --radius-2xl: calc(var(--radius) * 1.8);
    --radius-3xl: calc(var(--radius) * 2.2);
    --radius-4xl: calc(var(--radius) * 2.6);
}

:root:root {
    --background: #fafafa;
    --foreground: #242424;
    --card: #ffffff;
    --card-foreground: #242424;
    --popover: #ffffff;
    --popover-foreground: #242424;
    --primary: #0f6cbd;
    --primary-foreground: #ffffff;
    --secondary: #f5f5f5;
    --secondary-foreground: #242424;
    --muted: #f5f5f5;
    --muted-foreground: #616161;
    --accent: #ebf3fc;
    --accent-foreground: #0f6cbd;
    --destructive: #c50f1f;
    --border: #d1d1d1;
    --input: #d1d1d1;
    --ring: #0f6cbd;
    --chart-1: #0f6cbd;
    --chart-2: #107c10;
    --chart-3: #881798;
    --chart-4: #c50f1f;
    --chart-5: #ca5010;
    --radius: 0.375rem;
    --sidebar: #f5f5f5;
    --sidebar-foreground: #242424;
    --sidebar-primary: #0f6cbd;
    --sidebar-primary-foreground: #ffffff;
    --sidebar-accent: #ebf3fc;
    --sidebar-accent-foreground: #0f6cbd;
    --sidebar-border: #d1d1d1;
    --sidebar-ring: #0f6cbd;
}

.dark.dark {
    --background: #1f1f1f;
    --foreground: #f5f5f5;
    --card: #292929;
    --card-foreground: #f5f5f5;
    --popover: #292929;
    --popover-foreground: #f5f5f5;
    --primary: #479ef5;
    --primary-foreground: #081724;
    --secondary: #333333;
    --secondary-foreground: #f5f5f5;
    --muted: #333333;
    --muted-foreground: #c7c7c7;
    --accent: #0f3057;
    --accent-foreground: #d7e8fb;
    --destructive: #ff99a4;
    --border: rgb(255 255 255 / 14%);
    --input: rgb(255 255 255 / 18%);
    --ring: #479ef5;
    --chart-1: #479ef5;
    --chart-2: #54b054;
    --chart-3: #c386e8;
    --chart-4: #ff99a4;
    --chart-5: #f4bfab;
    --sidebar: #242424;
    --sidebar-foreground: #f5f5f5;
    --sidebar-primary: #479ef5;
    --sidebar-primary-foreground: #081724;
    --sidebar-accent: #0f3057;
    --sidebar-accent-foreground: #d7e8fb;
    --sidebar-border: rgb(255 255 255 / 14%);
    --sidebar-ring: #479ef5;
}

@layer base {
  * {
    @apply border-border outline-ring/50;
    }
  body {
    @apply bg-background text-foreground;
    }
  html:root {
    @apply font-sans;
    }
}
